import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"函数 | Dotfiles (ZH)","titleTemplate":":title","description":"增强终端体验的 Shell 函数。用于 API 测试、文件管理、系统操作等的工具。","frontmatter":{"title":"函数 | Dotfiles","description":"增强终端体验的 Shell 函数。用于 API 测试、文件管理、系统操作等的工具。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"函数 preview","canonical":"/zh/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"函数","pageType":"docs","schemaType":"WebPage","metaTitle":"函数 - Dotfiles (CN)","permalink":"/zh/functions/","meta":[{"name":"keywords","content":"函数, shell, bash, zsh, dotfiles, 生产力, 工具, api, 文件, 系统"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"增强终端体验的 Shell 函数。用于 API 测试、文件管理、系统操作等的工具。"},{"name":"twitter:title","content":"函数 - Dotfiles"},{"name":"og:title","content":"函数 - Dotfiles"},{"name":"og:description","content":"增强终端体验的 Shell 函数。用于 API 测试、文件管理、系统操作等的工具。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/functions/index.md","filePath":"zh/functions/index.md","lastUpdated":1773010926000}'),i={name:"zh/functions/index.md"};function o(s,t,n,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="函数" tabindex="-1">函数 <a class="header-anchor" href="#函数" aria-label="Permalink to &quot;函数&quot;">​</a></h1><p>跨 macOS、Linux 和 Windows 提高生产力的 Shell 工具。</p><h2 id="发现" tabindex="-1">发现 <a class="header-anchor" href="#发现" aria-label="Permalink to &quot;发现&quot;">​</a></h2><p>函数定义为单独的 <code>.sh</code> 文件。在 <code>chezmoi apply</code> 期间，它们会被聚合到 <code>~/.config/shell/functions.sh</code> 并由你的 shell 加载。</p><h2 id="开始使用" tabindex="-1">开始使用 <a class="header-anchor" href="#开始使用" aria-label="Permalink to &quot;开始使用&quot;">​</a></h2><h3 id="添加函数" tabindex="-1">添加函数 <a class="header-anchor" href="#添加函数" aria-label="Permalink to &quot;添加函数&quot;">​</a></h3><ol><li>创建一个新的 <code>.sh</code> 文件（例如 <code>myfunc.sh</code>）</li><li>添加你的函数定义</li><li>应用更改：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="api-测试" tabindex="-1">API 测试 <a class="header-anchor" href="#api-测试" aria-label="Permalink to &quot;API 测试&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">检查一个或多个 API 的健康状态</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">监控 API 响应时间</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">执行基本负载测试</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">调试带计时的 HTTP 请求</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="http-工具" tabindex="-1">HTTP 工具 <a class="header-anchor" href="#http-工具" aria-label="Permalink to &quot;HTTP 工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">查看 HTTP 头</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">检查 HTTP 状态码</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">测量 HTTP 计时指标</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">查看网站源代码</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">查找使用端口的进程</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="文件管理" tabindex="-1">文件管理 <a class="header-anchor" href="#文件管理" aria-label="Permalink to &quot;文件管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">创建带时间戳的备份</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">Base64 编码和解码</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">提取归档格式</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">以十六进制格式显示文件</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">批量重命名扩展名</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">检查文件或目录大小</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">创建 ZIP 归档</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="文件命名" tabindex="-1">文件命名 <a class="header-anchor" href="#文件命名" aria-label="Permalink to &quot;文件命名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">转换为 kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">转换为小写</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">转换为句首大写</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">转换为 snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">转换为首字母大写</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">转换为大写</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="系统工具" tabindex="-1">系统工具 <a class="header-anchor" href="#系统工具" aria-label="Permalink to &quot;系统工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">防止系统休眠</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">检测操作系统环境</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">清理可清除的磁盘空间</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">在 Finder 中切换隐藏文件</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">显示主机信息</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">查看命令使用统计</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">列出最近修改的文件</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">跨平台注销</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">列出用户进程</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">终端秒表</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">显示系统信息</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="caffeine-命令" tabindex="-1">Caffeine 命令 <a class="header-anchor" href="#caffeine-命令" aria-label="Permalink to &quot;Caffeine 命令&quot;">​</a></h3><p>防止系统休眠或激活屏幕保护程序。</p><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">启动 caffeine 守护进程</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">检查守护进程是否运行</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">保持屏幕唤醒</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">允许屏幕休眠</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">切换屏幕唤醒状态</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">关闭守护进程</td></tr></tbody></table><p>适用于 macOS（原生 <code>caffeinate</code>）、Linux（<code>xdg-screensaver</code>）和 Windows（PowerShell）。</p><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">生成强密码</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">生成 SSH 密钥对</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="导航" tabindex="-1">导航 <a class="header-anchor" href="#导航" aria-label="Permalink to &quot;导航&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">切换目录并列出内容</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">快速目录导航</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">将只读挂载为读写</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">删除目录</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">安全弹出磁盘</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="其他" tabindex="-1">其他 <a class="header-anchor" href="#其他" aria-label="Permalink to &quot;其他&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">函数</th><th style="text-align:left;">描述</th><th style="text-align:left;">用法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">终端黑客帝国效果</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">将目录添加到 PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">在 macOS 快速查看中打开</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">在 VS Code 中打开</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="兼容性" tabindex="-1">兼容性 <a class="header-anchor" href="#兼容性" aria-label="Permalink to &quot;兼容性&quot;">​</a></h2><ul><li><strong>macOS</strong> — 完全支持 macOS 特定工具</li><li><strong>Linux</strong> — 兼容常见发行版</li><li><strong>Windows</strong> — 通过 WSL、Cygwin 或 Git Bash 支持</li></ul><h2 id="帮助" tabindex="-1">帮助 <a class="header-anchor" href="#帮助" aria-label="Permalink to &quot;帮助&quot;">​</a></h2><p>每个函数都包含通过 <code>--help</code> 获取的文档：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(i,[["render",o]]);export{g as __pageData,y as default};
